import React from "react";
import "./Banner.css";

// Swiper imports
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";

function Banner() {
  return (
    <div className="banner">
      <Swiper spaceBetween={10} slidesPerView={1} autoplay={{ delay: 2000 }}>
       <SwiperSlide>
  <img 
  src="https://rukminim2.flixcart.com/fk-p-flap/1600/270/image/5b3f3b9cfdc8f5e4.jpg" 
  alt="Flipkart Sale Banner" 
/>
</SwiperSlide>

<SwiperSlide>
  <img 
    src="https://via.placeholder.com/1600x270?text=Big+Discount+Sale" 
    alt="Big Discount Sale Banner" 
  />
</SwiperSlide>

<SwiperSlide>
  <img 
    src="https://via.placeholder.com/1600x270?text=Best+Deals+Today" 
    alt="Best Deals Banner" 
  />
</SwiperSlide>
      </Swiper>
    </div>
  );
}

export default Banner;
